# typed: false
# frozen_string_literal: true

# Prebuilt-binary formula tracking devhost releases. Regenerated by
# GoReleaser on each release; hand-bumped to v0.7.0 once to recover from
# the period when the release workflow lacked tap credentials.
class Devhost < Formula
  desc "Per-directory port virtualization for dev servers"
  homepage "https://github.com/wickedev/devhost"
  version "0.7.0"
  license "MIT"

  on_macos do
    if Hardware::CPU.arm?
      url "https://github.com/wickedev/devhost/releases/download/v0.7.0/devhost_darwin_arm64.tar.gz"
      sha256 "0fb5482e72469bdaea1af46110b605a567ebed6ee15e1646726b54a80509f5cb"

      def install
        bin.install "devhost"
      end
    end
    if Hardware::CPU.intel?
      url "https://github.com/wickedev/devhost/releases/download/v0.7.0/devhost_darwin_amd64.tar.gz"
      sha256 "4ae8c98961c2b34710f97b5fa684f3326efab3990807905dff1d2d2359c33cc7"

      def install
        bin.install "devhost"
      end
    end
  end

  on_linux do
    if Hardware::CPU.arm? && Hardware::CPU.is_64_bit?
      url "https://github.com/wickedev/devhost/releases/download/v0.7.0/devhost_linux_arm64.tar.gz"
      sha256 "c43da42387826aa55100df916879cffe22bda34c352f4baec2c63f07db1af933"

      def install
        bin.install "devhost"
      end
    end
    if Hardware::CPU.intel? && Hardware::CPU.is_64_bit?
      url "https://github.com/wickedev/devhost/releases/download/v0.7.0/devhost_linux_amd64.tar.gz"
      sha256 "76a230053f6fc8cc0e50b44d7e5d328c46661051979c0fdb72de57848ad8038f"

      def install
        bin.install "devhost"
      end
    end
  end

  def caveats
    <<~EOS
      Run `devhost setup` to install the runtime shims and finish
      machine setup.
    EOS
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/devhost version")
  end
end
